class Bank {
public:
    void createAccount(int accountId, double initialBalance) {
        std::lock_guard<std::mutex> lock(mutex_);
        accounts_[accountId] = initialBalance;
    }

    void deposit(int accountId, double amount) {
        std::lock_guard<std::mutex> lock(mutex_);
        if (accounts_.find(accountId) != accounts_.end()) {
            accounts_[accountId] += amount;
        }
    }

    bool withdraw(int accountId, double amount) {
        std::lock_guard<std::mutex> lock(mutex_);
        if (accounts_.find(accountId) != accounts_.end() && accounts_[accountId] >= amount) {
            accounts_[accountId] -= amount;
            return true;
        }
        return false;
    }

    double getBalance(int accountId) {
        std::lock_guard<std::mutex> lock(mutex_);
        if (accounts_.find(accountId) != accounts_.end()) {
            return accounts_[accountId];
        }
        return 0.0;
    }

private:
    std::unordered_map<int, double> accounts_;
    std::mutex mutex_;
};

void transaction(Bank& bank, int accountId, double amount, bool isDeposit) {
    if (isDeposit) {
        bank.deposit(accountId, amount);
    } else {
        if (!bank.withdraw(accountId, amount)) {
            std::cout << "Withdrawal failed for account " << accountId << " due to insufficient funds.\n";
        }
    }
}

